        log_message('ERROR', "Plugin manifest not found: $ALLOWED_PLUGINS_MANIFEST");
        return 0;
    }

    # Manifest file must be owned by root and not world-writable
    my @stat = stat($ALLOWED_PLUGINS_MANIFEST);
    if ($stat[4] != 0) {
        log_message('SECURITY', "Manifest file not owned by root");
        return 0;
    }
    if ($stat[2] & 002) {
        log_message('SECURITY', "Manifest file is world-writable");
        return 0;
    }

    open(my $fh, '<', $ALLOWED_PLUGINS_MANIFEST) or do {
        log_message('ERROR', "Cannot open manifest: $!");
        return 0;
    };

    while (my $line = <$fh>) {
        chomp $line;
        $line =~ s/^\s+|\s+$//g;
        next if $line eq '' || $line =~ /^#/;

        # Expected format: filename sha256hash
