            my ($filename, $hash) = ($1, $2);
            $ALLOWED_PLUGIN_FILES{$filename} = $hash;
        } else {
            log_message('SECURITY', "Invalid manifest line: $line");
        }
    }
    close($fh);

    log_message('INFO', "Loaded " . scalar(keys %ALLOWED_PLUGIN_FILES) . " plugin entries from manifest");
    return 1;
}

