        return 0;
    }

    # File must not be world-writable or group-writable
    if ($stat[2] & 022) {
        log_message('SECURITY', "Plugin file has unsafe permissions: $filepath");
        return 0;
    }

    # Check file is not a symlink
    if (-l $filepath) {
