        return 0;
    }

    return 1;
}

sub validate_plugin_integrity {
    my ($filepath, $filename) = @_;

    my $expected_hash = $ALLOWED_PLUGIN_FILES{$filename};
    unless ($expected_hash) {
        log_message('SECURITY', "No hash found for plugin: $filename");
